# Проверка длин
issues = []
for nb in new_books:
    d = len(nb["description"])
    if d < 125 or d > 150:
        issues.append(f"Book {nb['id']} description: {d} chars")
    for i, t in enumerate(nb["thoughts"]):
        total = len(t["title"]) + len(t["example"])
        if total < 700 or total > 800:
            issues.append(f"Book {nb['id']} thought {i} ({t['title'][:30]}): {total} chars")

with open("/root/books/webapp/books.json") as f:
    books = json.load(f)
for nb in new_books:
    books.append(nb)
with open("/root/books/webapp/books.json", "w", encoding="utf-8") as f:
    json.dump(books, f, ensure_ascii=False, separators=(",", ":"))
if issues:
    print("Saved with issues:", len(issues))
    for iss in issues:
        print("ISSUE:", iss)
else:
    print("OK - saved 3 books")
